var { createTerminal } = require("./terminal");

var MAX_TERMINALS = 10;
var SCROLLBACK_MAX = 50 * 1024; // 50 KB per terminal

/**
 * Create a terminal manager that can create and manage multiple terminals.
 */
function TerminalManager() {
  this.terminals = [];
}

/**
 * Create a new terminal if under the limit.
 * @returns {object|null} The created terminal or null if limit reached.
 */
TerminalManager.prototype.create = function () {
  if (this.terminals.length > MAX_TERMINALS) {
    return null;
  }
  var term = createTerminal();
  this.terminals.push(term);
  return term;
};

/**
 * Get the total scrollback size across all terminals.
 * @returns {number} Total scrollback size in bytes.
 */
TerminalManager.prototype.getScrollbackSize = function () {
  return this.terminals.reduce(function (acc, term) {
    return acc + term.getScrollbackSize();
  }, 0);
};

/**
 * Check if scrollback size exceeds max allowed.
 * @returns {boolean}
 */
TerminalManager.prototype.isScrollbackExceeded = function () {
  return this.getScrollbackSize() > SCROLLBACK_MAX;
};

module.exports = {
  TerminalManager,
};
